from flask import Flask, request, jsonify
import psycopg2

app = Flask(__name__)

# Database connection parameters
DB_HOST = 'your_db_host'
DB_NAME = 'your_db_name'
DB_USER = 'your_db_user'
DB_PASSWORD = 'your_db_password'

def get_db_connection():
    conn = psycopg2.connect(host=DB_HOST, database=DB_NAME, user=DB_USER, password=DB_PASSWORD)
    return conn

@app.route('/query', methods=['GET'])
def query_data():
    table_name = request.args.get('table')
    columns = request.args.get('columns')
    filter_condition = request.args.get('filter')

    if not table_name or not columns:
        return jsonify({'error': 'Table name and columns are required'}), 400

    # Sanitize input to prevent SQL injection
    safe_table_name = psycopg2.extensions.adapt(table_name).getquoted().decode()
    safe_columns = psycopg2.extensions.adapt(columns).getquoted().decode()

    query = f"SELECT {safe_columns} FROM {safe_table_name}"
    
    if filter_condition:
        safe_filter_condition = psycopg2.extensions.adapt(filter_condition).getquoted().decode()
        query += f" WHERE {safe_filter_condition}"

    conn = get_db_connection()
    cur = conn.cursor()
    try:
        cur.execute(query)
        result = cur.fetchall()
        columns = [desc[0] for desc in cur.description]
        return jsonify({'columns': columns, 'data': result})
    except Exception as e:
        return jsonify({'error': str(e)}), 500
    finally:
        cur.close()
        conn.close()

if __name__ == '__main__':
    app.run(debug=True)